INSERT INTO `quizzes` (`id`, `title`, `description`, `is_premium`, `questions`, `created_at`) VALUES
('archetype', 'Архетип личности', 'Определите свой архетип личности по Юнгу', 0, '[{\"theme\": \"Искатель\", \"options\": [\"Совсем не согласен\", \"Скорее не согласен\", \"Нейтрально\", \"Скорее согласен\", \"Полностью согласен\"], \"question\": \"Я стремлюсь к приключениям и исследованию нового.\"}, {\"theme\": \"Герой\", \"options\": [\"Совсем не согласен\", \"Скорее не согласен\", \"Нейтрально\", \"Скорее согласен\", \"Полностью согласен\"], \"question\": \"Я чувствую себя героем, который преодолевает трудности ради других.\"}, {\"theme\": \"Творец\", \"options\": [\"Совсем не согласен\", \"Скорее не согласен\", \"Нейтрально\", \"Скорее согласен\", \"Полностью согласен\"], \"question\": \"Я люблю создавать что-то новое и уникальное.\"}, {\"theme\": \"Заботливый\", \"options\": [\"Совсем не согласен\", \"Скорее не согласен\", \"Нейтрально\", \"Скорее согласен\", \"Полностью согласен\"], \"question\": \"Я стремлюсь к гармонии и заботе о других людях.\"}, {\"theme\": \"Искатель\", \"options\": [\"Совсем не согласен\", \"Скорее не согласен\", \"Нейтрально\", \"Скорее согласен\", \"Полностью согласен\"], \"question\": \"Я часто ищу новые горизонты и не боюсь перемен.\"}, {\"theme\": \"Герой\", \"options\": [\"Совсем не согласен\", \"Скорее не согласен\", \"Нейтрально\", \"Скорее согласен\", \"Полностью согласен\"], \"question\": \"Я готов бороться за свои убеждения и защищать слабых.\"}, {\"theme\": \"Творец\", \"options\": [\"Совсем не согласен\", \"Скорее не согласен\", \"Нейтрально\", \"Скорее согласен\", \"Полностью согласен\"], \"question\": \"Я выражаю себя через творчество и искусство.\"}, {\"theme\": \"Заботливый\", \"options\": [\"Совсем не согласен\", \"Скорее не согласен\", \"Нейтрально\", \"Скорее согласен\", \"Полностью согласен\"], \"question\": \"Я всегда готов помочь другим, даже в ущерб себе.\"}]', '2026-03-11 13:26:01'),
('attachment', 'Тип привязанности', 'Узнайте, как вы выстраиваете отношения с другими', 0, '[{\"theme\": \"Secure\", \"options\": [\"Совсем не согласен\", \"Скорее не согласен\", \"Нейтрально\", \"Скорее согласен\", \"Полностью согласен\"], \"question\": \"Я чувствую себя комфортно, доверяя близким людям.\"}, {\"theme\": \"Anxious\", \"options\": [\"Совсем не согласен\", \"Скорее не согласен\", \"Нейтрально\", \"Скорее согласен\", \"Полностью согласен\"], \"question\": \"Мне часто кажется, что близкие люди могут меня отвергнуть.\"}, {\"theme\": \"Avoidant\", \"options\": [\"Совсем не согласен\", \"Скорее не согласен\", \"Нейтрально\", \"Скорее согласен\", \"Полностью согласен\"], \"question\": \"Я предпочитаю держать дистанцию в отношениях, чтобы не быть уязвимым.\"}, {\"theme\": \"Anxious\", \"options\": [\"Совсем не согласен\", \"Скорее не согласен\", \"Нейтрально\", \"Скорее согласен\", \"Полностью согласен\"], \"question\": \"Мне важно чувствовать поддержку партнера, чтобы быть уверенным в отношениях.\"}, {\"theme\": \"Secure\", \"options\": [\"Совсем не согласен\", \"Скорее не согласен\", \"Нейтрально\", \"Скорее согласен\", \"Полностью согласен\"], \"question\": \"Я легко открываюсь и делюсь своими чувствами с близкими.\"}, {\"theme\": \"Avoidant\", \"options\": [\"Совсем не согласен\", \"Скорее не согласен\", \"Нейтрально\", \"Скорее согласен\", \"Полностью согласен\"], \"question\": \"Я избегаю глубоких эмоциональных связей, чтобы не зависеть от других.\"}, {\"theme\": \"Anxious\", \"options\": [\"Совсем не согласен\", \"Скорее не согласен\", \"Нейтрально\", \"Скорее согласен\", \"Полностью согласен\"], \"question\": \"Я часто переживаю, что мои отношения могут закончиться.\"}, {\"theme\": \"Secure\", \"options\": [\"Совсем не согласен\", \"Скорее не согласен\", \"Нейтрально\", \"Скорее согласен\", \"Полностью согласен\"], \"question\": \"Я чувствую себя спокойно, когда близкие рядом, но не цепляюсь за них.\"}]', '2026-03-11 13:26:01'),
('paei', 'Тип личности по Адизесу (PAEI)', 'Определите свой стиль управления и лидерства', 0, '[{\"theme\": \"A\", \"options\": [\"Всегда идеальный порядок.\", \"В основном порядок, хоть и не идеальный.\", \"Всегда творческий беспорядок.\"], \"question\": \"Какая у вас ситуация с порядком на рабочем столе?\"}, {\"theme\": \"A\", \"options\": [\"Это 100% обо мне. Я совершенствую и улучшаю, пока не буду полностью доволен качеством.\", \"Не всегда. И не обязательно идеально. Но иногда это требуется.\", \"Перфекционизм — это вообще не про меня.\"], \"question\": \"Насколько верно утверждение, что вы всегда стремитесь выполнить свою работу идеально?\"}, {\"theme\": \"A\", \"options\": [\"Однозначно да.\", \"Только тогда, когда это очень важно.\", \"Нет.\"], \"question\": \"Можете ли вы сказать про себя, что вы крайне внимательны к деталям?\"}, {\"theme\": \"A\", \"options\": [\"Заранее готовлю список и покупаю по нему.\", \"Примерно представляю, что мне нужно или что хочу приготовить. Беру продукты под эту задачу. Но по ходу могу поменять мнение.\", \"Решаю на месте, что хочу купить сейчас.\"], \"question\": \"Как обычно покупаете продукты в магазине?\"}, {\"theme\": \"A\", \"options\": [\"Они обязательны к 100% соблюдению. Их нельзя нарушать никогда, т.к. это путь к хаосу.\", \"Процедуры важны, но ими можно пренебречь, если надо получить результат в срок.\", \"Не люблю формальные процедуры и правила, стараюсь работать без них.\"], \"question\": \"Каково ваше отношение к соблюдению процедур, правил и технологических процессов в работе?\"}, {\"theme\": \"P\", \"options\": [\"Да, когда поджимает срок, а результат сделать необходимо.\", \"В принципе могу, но не регулярно, стараюсь минимизировать такие ситуации.\", \"Стресс и давление выбивают меня из колеи.\"], \"question\": \"Можете ли вы сказать о себе, что умеете работать в условиях стресса?\"}, {\"theme\": \"P\", \"options\": [\"Когда вижу, что результат под угрозой, погружаюсь, чтобы найти решение проблемы.\", \"Когда случилась проблема, которую без меня не урегулировать.\", \"Не погружаюсь в несвойственные мне проблемы, каждый специалист должен заниматься своим делом.\"], \"question\": \"В каких случаях вы готовы детально погрузиться в проблематику, которая не относится к вашим непосредственным обязанностям?\"}, {\"theme\": \"P\", \"options\": [\"Если по-другому намеченную задачу не выполнить, то точно готов. Качество можно подтянуть позже.\", \"Скорее готов, но если потери качества будут незначительны.\", \"Нет, лучше вообще не сделать, чем сделать плохо.\"], \"question\": \"Готовы ли вы пожертвовать качеством ради результата?\"}, {\"theme\": \"A\", \"options\": [\"Нет. Я предпочитаю больше действовать, меньше размышлять. Додумывать и дорабатывать можно уже начатое дело.\", \"Частично. Я думаю прежде, чем что-то сделать, но недолго.\", \"Да. Прежде чем что-то сделать, нужно обдумать все детали.\"], \"question\": \"7 раз отмерь, один раз отрежь — эта поговорка про вас?\"}, {\"theme\": \"P\", \"options\": [\"Для меня крайне важно регулярно подводить итоги и видеть результаты своей работы, хотя бы промежуточные. Это меня мотивирует двигаться дальше.\", \"Лучше, когда на коротких отрезках времени измеримый результат виден.\", \"Меня не смущает, если результат будет виден нескоро (например, когда выполняется глобальная задача, или когда я работаю на качество).\"], \"question\": \"Насколько для вас важно видеть наглядный результат своей деятельности?\"}, {\"theme\": \"E\", \"options\": [\"Постоянно, я основной источник идей и нововведений.\", \"Периодически выступаю, но к чему-то слишком революционному отношусь осторожно.\", \"Предпочитаю проверенные инструменты и методы.\"], \"question\": \"Как часто вы выступаете новатором в рабочем коллективе и в среде друзей?\"}, {\"theme\": \"E\", \"options\": [\"Инициатива — это моя главная фишка. Я постоянно делаю первый шаг и являюсь идейным вдохновителем для других людей.\", \"Регулярно бываю инициатором разных действий и событий, на работе и в личной жизни.\", \"Мне комфортнее быть не инициатором, а участником чьих-то инициатив.\"], \"question\": \"Насколько вы инициативны?\"}, {\"theme\": \"E\", \"options\": [\"Цель на ближайший год — прирост 60 клиентов, у вас полная свобода действий в рамках бюджета.\", \"Ваша цель на квартал — прирост 15 новых клиентов. Прошу еженедельно информировать меня о выполненных мероприятиях и результатах.\", \"Ваша цель на ближайший месяц — привлечь 5 новых клиентов. Для этого до пятницы нужно придумать 3 варианта сбытовых акций для согласования со мной, а также подготовить список не менее 500 потенциальных клиентов для холодных звонков. На встрече в пятницу запланируем дальнейшие действия.\"], \"question\": \"Какой из предложенных вариантов постановки цели вам больше подходит?\"}, {\"theme\": \"E\", \"options\": [\"Это лучшие решения. Они чаще всего бывают яркими и выигрышными.\", \"Иногда такие решения здорово срабатывают, но я применяю их не постоянно.\", \"Нестандартные решения — это не мой конёк.\"], \"question\": \"Как вы относитесь к нестандартным решениям?\"}, {\"theme\": \"E\", \"options\": [\"Я готов рисковать, если за этим вижу что-то интересное или выдающееся. Часто за счёт этого выигрываю.\", \"Не отрицаю возможность рискнуть, но внимательно взвешиваю за и против.\", \"Стараюсь свести риски к минимуму.\"], \"question\": \"Как вы относитесь к риску?\"}, {\"theme\": \"I\", \"options\": [\"Без них невозможно строить рабочий процесс, т.к. очная коммуникация формирует единые взгляды и ценности, объединяет команду.\", \"Да, чтобы обеспечить прозрачность информации и принять некоторые совместные решения. Они должны быть недолгими и нечастыми.\", \"Совещания — это бесполезные пожиратели времени.\"], \"question\": \"Нужны ли для рабочего процесса совещания?\"}, {\"theme\": \"I\", \"options\": [\"Всем участникам учиться слышать друг друга и использовать конфликт для поиска наилучшего решения.\", \"Как можно быстрее погасить конфликт, чтобы он не мешал рабочему процессу.\", \"Запретить открытую конфронтацию и споры на рабочем месте.\"], \"question\": \"Что на ваш взгляд нужно делать с конфликтами в коллективе?\"}, {\"theme\": \"I\", \"options\": [\"Я 100% командный игрок.\", \"Лучше работать в команде, но можно и без неё.\", \"Предпочитаю работать индивидуально и отвечать только за собственный результат.\"], \"question\": \"Как вы относитесь к командной работе?\"}, {\"theme\": \"I\", \"options\": [\"Когда выполняют интересные задачи в команде единомышленников.\", \"Когда их уважают руководитель и коллеги.\", \"Когда им хорошо платят за работу.\"], \"question\": \"Когда люди хорошо делают свое дело?\"}, {\"theme\": \"I\", \"options\": [\"Я понимаю, что для соседа это элемент его жизни, и он не специально доставляет дискомфорт. Поговорю с ним и попробую найти компромисс.\", \"Я не в восторге от переговоров на конфликтные темы, но придётся поговорить с соседом.\", \"Законно ли курение на балконе? Сделаю предупреждение. Если не поможет, обращусь к участковому.\"], \"question\": \"Ваш сосед снизу часто курит на балконе и этим доставляет вам дискомфорт. Ваше отношение к ситуации и действия.\"}, {\"theme\": \"P\", \"options\": [\"Неполучение требуемого результата в срок.\", \"Нарушение порядка, процедур, правил. Отсутствие процессов и документации.\", \"Непонимание стратегии, отсутствие возможности самостоятельно достигать долгосрочные сложные цели.\", \"Конфликты, непонимание, неуважение между людьми. Отсутствие командного духа.\"], \"question\": \"Что в работе вызывает у вас максимальный стресс?\"}, {\"theme\": \"P\", \"options\": [\"Работу, на которой будет виден конкретный измеримый результат моей деятельности. И за этот результат будет справедливое вознаграждение.\", \"Работу, где необходимо умение организовать процесс и где на первом месте — качество выполнения задач.\", \"С долгосрочной целью, требующую творческого подхода и нестандартных решений.\", \"Работу, требующую качественного взаимодействия с людьми.\"], \"question\": \"Какую работу вы бы предпочли?\"}, {\"theme\": \"P\", \"options\": [\"Как это решение повлияет на ближайший результат.\", \"Взвешиваю все «за» и «против», оцениваю соответствие установленным процессам и правилам.\", \"Как это решение влияет на глобальную цель, привносит ли оно что-то новое прогрессивное в деятельность.\", \"Решение должно соответствовать моим внутренним принципам и легко приниматься коллективом.\"], \"question\": \"На что вы ориентируетесь при принятии решений?\"}, {\"theme\": \"P\", \"options\": [\"Наращу объемы работ и темпы (сейчас загружусь по полной ради результата, позже отдохну).\", \"Буду продолжать действовать по установленной технологии или процедуре. При этом постараюсь выполнять её быстрее.\", \"Буду искать новый нестандартный выход из ситуации.\", \"Обращусь за поддержкой к коллегам.\"], \"question\": \"Перед вами стоит сложная для вас рабочая задача, и сроки сильно поджимают. Что вы предпримете в первую очередь?\"}]', '2026-03-11 13:26:01'),
('strengths', 'Тест по методике Клифтона', 'Узнайте свои сильные стороны и как их использовать', 1, '[{\"theme\": \"Адаптивность\", \"options\": [\"Совсем не характерно\", \"Малозаметно\", \"Частично\", \"Достаточно характерно\", \"Полностью характерно\"], \"question\": \"Я легко подстраиваюсь под неожиданно меняющиеся ситуации и предпочитаю действовать по обстоятельствам.\"}, {\"theme\": \"Аналитик\", \"options\": [\"Совсем не характерно\", \"Малозаметно\", \"Частично\", \"Достаточно характерно\", \"Полностью характерно\"], \"question\": \"Мне нравится разбирать сложную информацию и выявлять закономерности прежде, чем принимать решение.\"}, {\"theme\": \"Аранжировщик (Организация)\", \"options\": [\"Совсем не характерно\", \"Малозаметно\", \"Частично\", \"Достаточно характерно\", \"Полностью характерно\"], \"question\": \"Я люблю планировать, структурировать процессы и создавать понятные системы.\"}, {\"theme\": \"Авангард (Инициативность)\", \"options\": [\"Совсем не характерно\", \"Малозаметно\", \"Частично\", \"Достаточно характерно\", \"Полностью характерно\"], \"question\": \"Я часто начинаю новые проекты и не жду, пока условие станет идеальным.\"}, {\"theme\": \"Гармония\", \"options\": [\"Совсем не характерно\", \"Малозаметно\", \"Частично\", \"Достаточно характерно\", \"Полностью характерно\"], \"question\": \"Я стремлюсь находить общие точки зрения и избегать ненужных споров в команде.\"}, {\"theme\": \"Гиперфокус (Выполнение)\", \"options\": [\"Совсем не характерно\", \"Малозаметно\", \"Частично\", \"Достаточно характерно\", \"Полностью характерно\"], \"question\": \"Когда беру задачу, склонен погружаться глубоко и доводить её до конца.\"}, {\"theme\": \"Доверие (Верность)\", \"options\": [\"Совсем не характерно\", \"Малозаметно\", \"Частично\", \"Достаточно характерно\", \"Полностью характерно\"], \"question\": \"Для меня важно, чтобы люди держали слово; я строю долгосрочные и надёжные связи.\"}, {\"theme\": \"Видение (Стратегическое мышление)\", \"options\": [\"Совсем не характерно\", \"Малозаметно\", \"Частично\", \"Достаточно характерно\", \"Полностью характерно\"], \"question\": \"Я легко вижу большие перспективы и могу представить разные пути развития.\"}, {\"theme\": \"Ведущий (Командование)\", \"options\": [\"Совсем не характерно\", \"Малозаметно\", \"Частично\", \"Достаточно характерно\", \"Полностью характерно\"], \"question\": \"Я не боюсь брать на себя ответственность и вести людей за собой в сложных ситуациях.\"}, {\"theme\": \"Вдохновитель (Коммуникация)\", \"options\": [\"Совсем не характерно\", \"Малозаметно\", \"Частично\", \"Достаточно характерно\", \"Полностью характерно\"], \"question\": \"Мне нравится увлекательно объяснять идеи и убеждать других в своей точке зрения.\"}, {\"theme\": \"Заботливость (Поддержка)\", \"options\": [\"Совсем не характерно\", \"Малозаметно\", \"Частично\", \"Достаточно характерно\", \"Полностью характерно\"], \"question\": \"Я замечаю потребности людей и стараюсь помогать, даже если это требует ресурсов.\"}, {\"theme\": \"Инициатор (Самомотивация)\", \"options\": [\"Совсем не характерно\", \"Малозаметно\", \"Частично\", \"Достаточно характерно\", \"Полностью характерно\"], \"question\": \"Я внутренне мотивирован достигать целей без внешнего давления.\"}, {\"theme\": \"Интеллект (Любознательность)\", \"options\": [\"Совсем не характерно\", \"Малозаметно\", \"Частично\", \"Достаточно характерно\", \"Полностью характерно\"], \"question\": \"Я постоянно ищу новые знания и люблю учиться ради понимания.\"}, {\"theme\": \"Креативность (Идеи)\", \"options\": [\"Совсем не характерно\", \"Малозаметно\", \"Частично\", \"Достаточно характерно\", \"Полностью характерно\"], \"question\": \"Я часто генерирую нестандартные идеи и вижу необычные сочетания вещей.\"}, {\"theme\": \"Командный игрок\", \"options\": [\"Совсем не характерно\", \"Малозаметно\", \"Частично\", \"Достаточно характерно\", \"Полностью характерно\"], \"question\": \"Я эффективно работаю в группе, поддерживаю других