INSERT INTO `tarot_interpretations` (`id`, `card_id`, `spread_id`, `position_index`, `interpretation`, `created_at`) VALUES
('celtic_chariot_0', 'chariot', 'celtic', 0, 'Ситуация требует решительных действий и преодоления препятствий на пути к цели.', '2026-03-11 15:36:54'),
('celtic_chariot_1', 'chariot', 'celtic', 1, 'Препятствие: импульсивность или движение в противоположных направлениях.', '2026-03-11 15:36:54'),
('celtic_chariot_2', 'chariot', 'celtic', 2, 'Далекое прошлое: прошлые победы и преодоленные препятствия дали опыт и уверенность.', '2026-03-11 15:36:54'),
('celtic_chariot_3', 'chariot', 'celtic', 3, 'Недавние решительные действия и преодоление препятствий привели к текущему положению.', '2026-03-11 15:36:55'),
('celtic_chariot_4', 'chariot', 'celtic', 4, 'Возможное будущее: победа и достижение целей через решительные действия.', '2026-03-11 15:36:55'),
('celtic_chariot_5', 'chariot', 'celtic', 5, 'Ближайшее будущее: период активных действий и преодоления препятствий на пути к цели.', '2026-03-11 15:36:55'),
('celtic_chariot_6', 'chariot', 'celtic', 6, 'Ваш подход: действуйте решительно и целенаправленно. Преодолевайте препятствия с уверенностью.', '2026-03-11 15:36:55'),
('celtic_chariot_7', 'chariot', 'celtic', 7, 'Внешние влияния: динамичная среда и конкурентная обстановка стимулируют к действиям.', '2026-03-11 15:36:56'),
('celtic_chariot_8', 'chariot', 'celtic', 8, 'Надежды и страхи: вы надеетесь на победу и достижения, но боитесь потерять контроль.', '2026-03-11 15:36:56'),
('celtic_chariot_9', 'chariot', 'celtic', 9, 'Итоговый результат: решительные действия и преодоление препятствий приведут к победе.', '2026-03-11 15:36:56'),
('celtic_death_0', 'death', 'celtic', 0, 'В основе ситуации лежит завершение одного этапа и начало нового.', '2026-03-11 15:36:54'),
('celtic_death_1', 'death', 'celtic', 1, 'Препятствие: сопротивление необходимым изменениям или страх перед новым.', '2026-03-11 15:36:54'),
('celtic_death_2', 'death', 'celtic', 2, 'Далекое прошлое: завершение важного этапа открыло путь для трансформации.', '2026-03-11 15:36:54'),
('celtic_death_3', 'death', 'celtic', 3, 'Недавнее завершение важного этапа освободило место для нового развития.', '2026-03-11 15:36:55'),
